structure HornRule (α : Type u) where
  antecedent : Set α
  consequent : Set α

def Apply {α : Type u} (Γ : Set (HornRule α)) (s : Set α) : Set α :=
  s ∪ {p | ∃ r ∈ Γ, r.antecedent ⊆ s ∧ p ∈ r.consequent}

def MonotoneUpTo {α : Type u} (T : ℕ) (s : ℕ → Set α) : Prop :=
  ∀ ⦃t : ℕ⦄, t < T → s t ⊆ s (t + 1)

def MaximalUpTo {α : Type u} (Γ : Set (HornRule α)) (T : ℕ) (s : ℕ → Set α) : Prop :=
  ∀ ⦃t : ℕ⦄, t < T → ∀ ⦃r : HornRule α⦄, r ∈ Γ → r.antecedent ⊆ s t → r.consequent ⊆ s (t + 1)

def SoundUpTo {α : Type u} (Γ : Set (HornRule α)) (T : ℕ) (s : ℕ → Set α) : Prop :=
  ∀ ⦃t : ℕ⦄, t < T → ∀ ⦃p : α⦄, p ∈ s (t + 1) → p ∈ s t ∨ ∃ r ∈ Γ, r.antecedent ⊆ s t ∧ p ∈ r.consequent

def MMSWith {α : Type u} (Γ : Set (HornRule α)) (Φ : Set α) (T : ℕ) (s : ℕ → Set α) : Prop :=
  s 0 = Φ ∧ MonotoneUpTo T s ∧ MaximalUpTo Γ T s ∧ SoundUpTo Γ T s

def GeneratedByApply {α : Type u} (Γ : Set (HornRule α)) (Φ : Set α) (T : ℕ) (s : ℕ → Set α) : Prop :=
  s 0 = Φ ∧ ∀ ⦃t : ℕ⦄, t < T → s (t + 1) = Apply Γ (s t)

