def Simplex (n : ℕ) : Set (Fin n → ℝ) :=
  {p | (∀ i, 0 ≤ p i) ∧ (∑ i, p i) = 1}

def Bregman1D (φ : ℝ → ℝ) (x y : ℝ) : ℝ :=
  φ x - φ y - deriv φ y * (x - y)

def BregmanSep {n : ℕ} (φ : ℝ → ℝ) (a b : Fin n → ℝ) : ℝ :=
  ∑ i, Bregman1D φ (a i) (b i)

def PadZero (k V : ℕ) (hk : k ≤ V) (q : Fin k → ℝ) : Fin V → ℝ :=
  fun i =>
    if h : i.1 < k then
      q ⟨i.1, h⟩
    else
      0

def PrimalValid (φ : ℝ → ℝ) : Prop :=
  ConvexOn ℝ (Set.Icc (0 : ℝ) 1) φ ∧
  ContDiffOn ℝ 1 φ (Set.Icc (0 : ℝ) 1) ∧
  StrictConvexOn ℝ (Set.Ioo (0 : ℝ) 1) φ

def DualValid (φ : ℝ → ℝ) : Prop :=
  ContDiffOn ℝ 3 φ (Set.Ioc (0 : ℝ) 1) ∧
  Filter.Tendsto (fun x : ℝ => x * deriv (deriv φ) x)
    (nhdsWithin (0 : ℝ) (Set.Ioi (0 : ℝ)))
    (nhds (0 : ℝ)) ∧
  (∀ x : ℝ, 0 < x → x ≤ 1 →
    StrictConvexOn ℝ (Set.Icc x 1) (fun y => Bregman1D φ x y)) ∧
  StrictConvexOn ℝ (Set.Ioc (0 : ℝ) 1) (fun y => Bregman1D φ 0 y)

def CostPrimal {V : ℕ} (φ : ℝ → ℝ) (p : Fin V → ℝ) (lam : ℝ) (k : ℕ) : ℝ :=
  sInf {r : ℝ | ∃ hk : k ≤ V, ∃ q : Fin k → ℝ, q ∈ Simplex k ∧
    r = BregmanSep φ (PadZero k V hk q) p + lam * (k : ℝ)}

def CostDual {V : ℕ} (φ : ℝ → ℝ) (p : Fin V → ℝ) (lam : ℝ) (k : ℕ) : ℝ :=
  sInf {r : ℝ | ∃ hk : k ≤ V, ∃ q : Fin k → ℝ, q ∈ Simplex k ∧
    r = BregmanSep φ p (PadZero k V hk q) + lam * (k : ℝ)}

def DiscretelyConvexOn (h : ℕ → ℝ) (V : ℕ) : Prop :=
  ∀ k : ℕ, 2 ≤ k → k ≤ V - 1 →
    ((h (k + 1) - h k) - (h k - h (k - 1)) ≥ 0)

