abbrev MatrixR (n d : ℕ) := Matrix (Fin n) (Fin d) ℝ

def rowScore {n d : ℕ} (Q K : MatrixR n d) (i r : Fin n) : ℝ :=
  ∑ t : Fin d, Q i t * K r t

def attentionWeight {n d : ℕ} (Q K : MatrixR n d) (i r : Fin n) : ℝ :=
  Real.exp (rowScore Q K i r)

def attentionNormalizer {n d : ℕ} (Q K : MatrixR n d) (i : Fin n) : ℝ :=
  ∑ s : Fin n, attentionWeight Q K i s

def selfAttentionEntry {n d : ℕ} (Q K V : MatrixR n d) (i : Fin n) (j : Fin d) : ℝ :=
  ∑ r : Fin n, (attentionWeight Q K i r / attentionNormalizer Q K i) * V r j

def selfAttention {n d : ℕ} (Q K V : MatrixR n d) : MatrixR n d :=
  fun i j => selfAttentionEntry Q K V i j

def valueInfinityNormBigOLog {n d : ℕ} (V : MatrixR n d) : Prop :=
