def entrywiseRelativeError {n d : ℕ} (Q K V Ohat : MatrixR n d) (ε : ℝ) : Prop :=
  ∀ i : Fin n, ∀ j : Fin d,
    |Ohat i j - selfAttention Q K V i j| ≤ ε * selfAttention Q K V i j

